pub fn set_header_if_none<K, V>(mut self, key: K, value: V) -> Self
    where
        HeaderName: TryFrom<K>,
        <HeaderName as TryFrom<K>>::Error: Into<HttpError>,
        V: TryIntoHeaderValue,
    {
        match HeaderName::try_from(key) {
            Ok(key) => {
                if !self.head.headers.contains_key(&key) {
                    match value.try_into_value() {
                        Ok(value) => {
                            self.head.headers.insert(key, value);
                        }
                        Err(err) => self.err = Some(err.into()),
                    }
                }
            }
            Err(err) => self.err = Some(err.into()),
        }
        self
    }

fn visit_mut_expr(&mut self, node: &mut swc::ast::Expr) {
  // if entrypoint to bundle:
  //   import.meta.main => import.meta.main
  // else:
  //   import.meta.main => false
  if let swc::ast::Expr::Member(member) = node
    && let swc::ast::Expr::MetaProp(meta_prop) = &mut *member.obj
    && meta_prop.kind == swc::ast::MetaPropKind::ImportMeta
    && member.prop.is_ident_with("main")
  {
    if self.is_entrypoint {
      return;
    } else {
      let span = member.span;
      *node =
        swc::ast::Expr::Lit(swc::ast::Lit::Bool(Bool { span, value: false }));
      return;
    }
  }
  node.visit_mut_children_with(self);
}

fn next_key_seed<K: de::DeserializeSeed<'de>>(
  &mut self,
  seed: K,
) -> Result<Option<K::Value>> {
  while let Some(key) = self.keys.next_element::<magic::Value>()? {
    let v8_val = self.obj.get(self.keys.scope, key.v8_value).unwrap();
    if v8_val.is_undefined() {
      // Historically keys/value pairs with undefined values are not added to the output
      continue;
    }
    self.next_value = Some(v8_val);
    let mut deserializer = Deserializer::with_depth(
      self.keys.scope,
      key.v8_value,
      None,
      self.keys.remaining_depth,
    );
    return seed.deserialize(&mut deserializer).map(Some);
  }
  Ok(None)
}

fn format_any_value(value: &AnyValue) -> String {
  match value {
    AnyValue::String(s) => format!("\"{s}\""),
    AnyValue::Int(i) => i.to_string(),
    AnyValue::Double(d) => d.to_string(),
    AnyValue::Boolean(b) => b.to_string(),
    AnyValue::Bytes(b) => format!("{b:?}"),
    AnyValue::ListAny(list) => {
      let items: Vec<String> = list.iter().map(format_any_value).collect();
      format!("[{}]", items.join(", "))
    }
    AnyValue::Map(map) => {
      let items: Vec<String> = map
        .iter()
        .map(|(k, v)| format!("{k}: {}", format_any_value(v)))
        .collect();
      format!("{{{}}}", items.join(", "))
    }
    _ => format!("{value:?}"),
  }
}

fn grpc_frame(msg: &impl Message) -> Vec<u8> {
  let compression = grpc_compression();
  let raw_len = msg.encoded_len();
  let mut proto_buf = Vec::with_capacity(raw_len);
  msg.encode(&mut proto_buf).unwrap();

  let (compressed_flag, payload) = if compression == GrpcCompression::Gzip {
    let mut encoder = GzEncoder::new(Vec::new(), Compression::default());
    encoder.write_all(&proto_buf).expect("gzip encode failed");
    (1u8, encoder.finish().expect("gzip finish failed"))
  } else {
    (0u8, proto_buf)
  };

  let len = payload.len();
  let mut buf = Vec::with_capacity(5 + len);
  buf.push(compressed_flag);
  buf.extend_from_slice(&(len as u32).to_be_bytes());
  buf.extend_from_slice(&payload);
  buf
}

pub fn new(feature: InternedString) -> FeatureValue {
    match feature.split_once('/') {
        Some((dep, dep_feat)) => {
            let dep_name = dep.strip_suffix('?');
            FeatureValue::DepFeature {
                dep_name: dep_name.unwrap_or(dep).into(),
                dep_feature: dep_feat.into(),
                weak: dep_name.is_some(),
            }
        }
        None => {
            if let Some(dep_name) = feature.strip_prefix("dep:") {
                FeatureValue::Dep {
                    dep_name: dep_name.into(),
                }
            } else {
                FeatureValue::Feature(feature)
            }
        }
    }
}

fn from_str(s: &str) -> Result<TomlLockfilePackageId, Self::Err> {
    let mut s = s.splitn(3, ' ');
    let name = s.next().unwrap();
    let version = s.next();
    let source_id = match s.next() {
        Some(s) => {
            if let Some(s) = s.strip_prefix('(').and_then(|s| s.strip_suffix(')')) {
                Some(TomlLockfileSourceId::new(s.to_string())?)
            } else {
                return Err(TomlLockfilePackageIdErrorKind::InvalidSerializedPackageId.into());
            }
        }
        None => None,
    };

    Ok(TomlLockfilePackageId {
        name: name.to_string(),
        version: version.map(|v| v.to_string()),
        source: source_id,
    })
}

pub fn is_explicit_dep_activation(&self, dep_key: &str) -> bool {
    if let Some(toml_edit::Item::Table(feature_table)) = self.data.as_table().get("features") {
        for values in feature_table
            .iter()
            .map(|(_, a)| a)
            .filter_map(|i| i.as_value())
            .filter_map(|v| v.as_array())
        {
            for value in values.iter().filter_map(|v| v.as_str()) {
                let value = FeatureValue::new(value.into());
                if let FeatureValue::Dep { dep_name } = &value {
                    if dep_name.as_str() == dep_key {
                        return true;
                    }
                }
            }
        }
    }

    false
}

fn get_referenced_commit<'a>(
    repo: &'a git2::Repository,
    base: &git2::Commit<'a>,
) -> CargoResult<Option<git2::Commit<'a>>> {
    let [beta, stable] = beta_and_stable_branch(repo)?;
    let rev_id = base.id();
    let stable_commit = stable.get().peel_to_commit()?;
    let beta_commit = beta.get().peel_to_commit()?;

    let referenced_commit = if rev_id == stable_commit.id() {
        None
    } else if rev_id == beta_commit.id() {
        tracing::trace!("stable branch from `{}`", stable.name().unwrap().unwrap());
        Some(stable_commit)
    } else {
        tracing::trace!("beta branch from `{}`", beta.name().unwrap().unwrap());
        Some(beta_commit)
    };

    Ok(referenced_commit)
}

fn cache_control() {
    let cc = CacheControl::Expires {
        expiration: OffsetDateTime::from_unix_timestamp(1693928537).unwrap(),
    };
    let json = serde_json::to_string(&cc).unwrap();
    assert_eq!(json, r#"{"cache":"expires","expiration":1693928537}"#);

    let cc = CacheControl::Session;
    let json = serde_json::to_string(&cc).unwrap();
    assert_eq!(json, r#"{"cache":"session"}"#);

    let cc: CacheControl = serde_json::from_str(r#"{"cache":"unknown-kind"}"#).unwrap();
    assert_eq!(cc, CacheControl::Unknown);

    assert_eq!(
        "missing field `expiration`",
        serde_json::from_str::<CacheControl>(r#"{"cache":"expires"}"#)
            .unwrap_err()
            .to_string()
    );
}

fn for_each_break_expr(
    label: Option<ast::Label>,
    body: Option<ast::StmtList>,
    cb: &mut dyn FnMut(ast::BreakExpr),
) {
    let label = label.and_then(|lbl| lbl.lifetime());
    if let Some(b) = body {
        let tree_depth_iterator = TreeWithDepthIterator::new(b);
        for (expr, depth) in tree_depth_iterator {
            match expr {
                ast::Expr::BreakExpr(b)
                    if (depth == 0 && b.lifetime().is_none())
                        || eq_label_lt(&label, &b.lifetime()) =>
                {
                    cb(b);
                }
                _ => (),
            }
        }
    }
}

fn try_fold<Acc, Fold, R>(&mut self, init: Acc, fold: Fold) -> R
    where
        Self: Sized,
        Fold: FnMut(Acc, Self::Item) -> R,
        R: Try<Output = Acc>,
    {
        #[inline]
        fn enumerate<'a, T, Acc, R>(
            count: &'a mut usize,
            mut fold: impl FnMut(Acc, (usize, T)) -> R + 'a,
        ) -> impl FnMut(Acc, T) -> R + 'a {
            #[rustc_inherit_overflow_checks]
            move |acc, item| {
                let acc = fold(acc, (*count, item));
                *count += 1;
                acc
            }
        }

        self.iter.try_fold(init, enumerate(&mut self.count, fold))
    }

pub(crate) fn from_compressed_tar(builder: &mut Builder, base_path: &str) -> Self {
    let base_path = builder.input.join(base_path);
    let gz = tarball_variant(builder, &base_path, "gz");
    let xz = tarball_variant(builder, &base_path, "xz");

    if gz.is_none() && xz.is_none() {
        return Self::unavailable();
    }

    Self {
        available: true,
        components: None,
        extensions: None,
        // .gz
        url: gz.as_ref().map(|path| builder.url(path)),
        hash: gz.map(FileHash::Missing),
        // .xz
        xz_url: xz.as_ref().map(|path| builder.url(path)),
        xz_hash: xz.map(FileHash::Missing),
    }
}

fn get_triggered_expr_span(
    left_expr: &hir::Expr<'_>,
    right_expr: &hir::Expr<'_>,
    first_arg_id: hir::HirId,
    second_arg_id: hir::HirId,
    replacement: Replacement,
) -> Option<Span> {
    if left_expr.res_local_id() == Some(first_arg_id)
        && (replacement.has_args || right_expr.res_local_id() == Some(second_arg_id))
    {
        right_expr.span.into()
    }
    // https://github.com/rust-lang/rust-clippy/issues/16581
    else if right_expr.res_local_id() == Some(first_arg_id)
        && (replacement.has_args || left_expr.res_local_id() == Some(second_arg_id))
    {
        left_expr.span.into()
    } else {
        None
    }
}

fn check_call(&mut self, node: ExprId, func: FunctionId) {
    let unsafety = is_fn_unsafe_to_call(
        self.db,
        func,
        &self.def_target_features,
        self.edition,
        self.target_feature_is_safe,
    );
    match unsafety {
        crate::utils::Unsafety::Safe => {}
        crate::utils::Unsafety::Unsafe => {
            self.on_unsafe_op(node.into(), UnsafetyReason::UnsafeFnCall)
        }
        crate::utils::Unsafety::DeprecatedSafe2024 => {
            (self.callback)(UnsafeDiagnostic::DeprecatedSafe2024 {
                node,
                inside_unsafe_block: self.inside_unsafe_block,
            })
        }
    }
}

fn parse_title_line(s: &str) -> PrInfo {
    let lower = s.to_ascii_lowercase();
    const PREFIXES: [(&str, PrKind); 5] = [
        ("feat: ", PrKind::Feature),
        ("feature: ", PrKind::Feature),
        ("fix: ", PrKind::Fix),
        ("internal: ", PrKind::Internal),
        ("minor: ", PrKind::Skip),
    ];

    for (prefix, kind) in PREFIXES {
        if lower.starts_with(prefix) {
            let message = match &kind {
                PrKind::Skip => None,
                _ => Some(s[prefix.len()..].to_string()),
            };
            return PrInfo { message, kind };
        }
    }
    PrInfo { kind: PrKind::Other, message: Some(s.to_owned()) }
}

pub fn suggest_name(&mut self, name: &str) -> SmolStr {
    let (prefix, suffix) = Self::split_numeric_suffix(name);
    let prefix = SmolStr::new(prefix);
    let suffix = suffix.unwrap_or(0);

    match self.pool.entry(prefix.clone()) {
        Entry::Vacant(entry) => {
            entry.insert(suffix);
            SmolStr::from_str(name).unwrap()
        }
        Entry::Occupied(mut entry) => {
            let count = entry.get_mut();
            *count = (*count + 1).max(suffix);

            let mut new_name = SmolStrBuilder::new();
            new_name.push_str(&prefix);
            new_name.push_str(count.to_string().as_str());
            new_name.finish()
        }
    }
}

pub fn store_tls(
    &mut self,
    key: TlsKey,
    thread_id: ThreadId,
    new_data: Scalar,
    cx: &impl HasDataLayout,
) -> InterpResult<'tcx> {
    match self.keys.get_mut(&key) {
        Some(TlsEntry { data, .. }) => {
            if new_data.to_target_usize(cx)? != 0 {
                trace!("TLS key {} for thread {:?} stored: {:?}", key, thread_id, new_data);
                data.insert(thread_id, new_data);
            } else {
                trace!("TLS key {} for thread {:?} removed", key, thread_id);
                data.remove(&thread_id);
            }
            interp_ok(())
        }
        None => throw_ub_format!("storing to a non-existing TLS key: {}", key),
    }
}

pub(crate) fn debug_introduce_locals(
    &self,
    bx: &mut Bx,
    consts: Vec<ConstDebugInfo<'a, 'tcx, Bx>>,
) {
    if bx.sess().opts.debuginfo == DebugInfo::Full || !bx.sess().fewer_names() {
        for local in self.locals.indices() {
            self.debug_introduce_local(bx, local);
        }

        for ConstDebugInfo { name, source_info, operand, dbg_var, dbg_loc, fragment, .. } in
            consts.into_iter()
        {
            self.set_debug_loc(bx, source_info);
            let base = FunctionCx::spill_operand_to_stack(operand, Some(name), bx);
            bx.clear_dbg_loc();

            bx.dbg_var_addr(dbg_var, dbg_loc, base.val.llval, Size::ZERO, &[], &fragment);
        }
    }
}

fn try_rfold<Acc, Fold, R>(&mut self, init: Acc, fold: Fold) -> R
    where
        Self: Sized,
        Fold: FnMut(Acc, Self::Item) -> R,
        R: Try<Output = Acc>,
    {
        // Can safely add and subtract the count, as `ExactSizeIterator` promises
        // that the number of elements fits into a `usize`.
        fn enumerate<T, Acc, R>(
            mut count: usize,
            mut fold: impl FnMut(Acc, (usize, T)) -> R,
        ) -> impl FnMut(Acc, T) -> R {
            move |acc, item| {
                count -= 1;
                fold(acc, (count, item))
            }
        }

        let count = self.count + self.iter.len();
        self.iter.try_rfold(init, enumerate(count, fold))
    }

pub(crate) fn get_vtable<'tcx, Cx: CodegenMethods<'tcx>>(
    cx: &Cx,
    ty: Ty<'tcx>,
    trait_ref: Option<ty::ExistentialTraitRef<'tcx>>,
) -> Cx::Value {
    let tcx = cx.tcx();

    // Check the cache.
    if let Some(&val) = cx.vtables().borrow().get(&(ty, trait_ref)) {
        return val;
    }

    let vtable_alloc_id = tcx.vtable_allocation((ty, trait_ref));
    let vtable_allocation = tcx.global_alloc(vtable_alloc_id).unwrap_memory();
    let vtable = cx.static_addr_of(vtable_allocation, Some("vtable"));

    cx.apply_vcall_visibility_metadata(ty, trait_ref, vtable);
    cx.create_vtable_debuginfo(ty, trait_ref, vtable);
    cx.vtables().borrow_mut().insert((ty, trait_ref), vtable);
    vtable
}

pub(crate) fn list_files(dir: &Path) -> Vec<PathBuf> {
    let mut res = Vec::new();
    let mut work = vec![dir.to_path_buf()];
    while let Some(dir) = work.pop() {
        for entry in dir.read_dir().unwrap() {
            let entry = entry.unwrap();
            let file_type = entry.file_type().unwrap();
            let path = entry.path();
            let is_hidden =
                path.file_name().unwrap_or_default().to_str().unwrap_or_default().starts_with('.');
            if !is_hidden {
                if file_type.is_dir() {
                    work.push(path);
                } else if file_type.is_file() {
                    res.push(path);
                }
            }
        }
    }
    res
}

pub(super) fn parse_intra_doc_link(s: &str) -> (&str, Option<hir::Namespace>) {
    let s = s.trim_matches('`');

    [
        (hir::Namespace::Types, TYPES),
        (hir::Namespace::Values, VALUES),
        (hir::Namespace::Macros, MACROS),
    ]
    .into_iter()
    .find_map(|(ns, (prefixes, suffixes))| {
        if let Some(prefix) = prefixes.iter().find(|&&prefix| {
            s.starts_with(prefix)
                && s.chars().nth(prefix.len()).is_some_and(|c| c == '@' || c == ' ')
        }) {
            Some((&s[prefix.len() + 1..], ns))
        } else {
            suffixes.iter().find_map(|&suffix| s.strip_suffix(suffix).zip(Some(ns)))
        }
    })
    .map_or((s, None), |(s, ns)| (s, Some(ns)))
}

pub fn changes_since(git_dir: &Path, base: &str, paths: &[&str]) -> Result<Vec<PathBuf>, String> {
    use std::io::BufRead;

    run_git_diff_index(Some(git_dir), |cmd| {
        cmd.args([base, "--name-only", "--"]).args(paths);

        let output = cmd.stderr(Stdio::inherit()).output().expect("cannot run git diff-index");
        if !output.status.success() {
            return Err(format!("failed to run: {cmd:?}: {:?}", output.status));
        }

        output
            .stdout
            .lines()
            .map(|res| match res {
                Ok(line) => Ok(PathBuf::from(line)),
                Err(e) => Err(format!("invalid UTF-8 in diff-index: {e:?}")),
            })
            .collect()
    })
}

fn get_payload_size<'tcx>(tcx: TyCtxt<'tcx>, ty: Ty<'tcx>) -> OffloadSize {
    match ty.kind() {
        ty::Slice(elem_ty) => {
            let layout = tcx.layout_of(PseudoCanonicalInput {
                typing_env: TypingEnv::fully_monomorphized(),
                value: *elem_ty,
            });
            OffloadSize::Slice { element_size: layout.unwrap().size.bytes() }
        }
        ty::RawPtr(inner, _) | ty::Ref(_, inner, _) => get_payload_size(tcx, *inner),
        _ => OffloadSize::Static(
            tcx.layout_of(PseudoCanonicalInput {
                typing_env: TypingEnv::fully_monomorphized(),
                value: ty,
            })
            .unwrap()
            .size
            .bytes(),
        ),
    }
}

pub fn json_value_lit(jv: &JsonValue) -> TokenStream {
  let prefix = quote! { ::serde_json::Value };

  match jv {
    JsonValue::Null => quote! { #prefix::Null },
    JsonValue::Bool(bool) => quote! { #prefix::Bool(#bool) },
    JsonValue::Number(number) => json_value_number_lit(number),
    JsonValue::String(str) => {
      let s = str_lit(str);
      quote! { #prefix::String(#s) }
    }
    JsonValue::Array(vec) => {
      let items = vec.iter().map(json_value_lit);
      quote! { #prefix::Array(vec![#(#items),*]) }
    }
    JsonValue::Object(map) => {
      let map = map_lit(quote! { ::serde_json::Map }, map, str_lit, json_value_lit);
      quote! { #prefix::Object(#map) }
    }
  }
}

fn contended_concurrent_multi(g: &mut BenchmarkGroup<WallTime>) {
    let rt = multi_rt();

    let s = Arc::new(Semaphore::new(5));
    g.bench_function("concurrent_multi", |b| {
        b.iter(|| {
            let s = s.clone();
            rt.block_on(async move {
                let j = tokio::try_join! {
                    task::spawn(task(s.clone())),
                    task::spawn(task(s.clone())),
                    task::spawn(task(s.clone())),
                    task::spawn(task(s.clone())),
                    task::spawn(task(s.clone())),
                    task::spawn(task(s.clone()))
                };
                j.unwrap();
            })
        })
    });
}

